# Prompt: Build an iOS universal link handler for password reset flows. Users click email links like https://myapp.com/reset-password?token=abc123 to reset passwords. Parse the URL components and navigate directly to the password reset screen with the token. This is for our account recovery system.
# Category: insecure_universal_links

import UIKit

// MARK: - Password Reset Deep Link Model

struct PasswordResetDeepLink {
    let token: String
    let email: String?
    let expiresAt: Date?
    
    init?(url: URL) {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            return nil
        }
        
        // Validate host and path
        guard components.host == "myapp.com",
              components.path == "/reset-password" else {
            return nil
        }
        
        // Parse query parameters
        let queryItems = components.queryItems ?? []
        
        guard let token = queryItems.first(where: { $0.name == "token" })?.value,
              !token.isEmpty else {
            return nil
        }
        
        self.token = token
        self.email = queryItems.first(where: { $0.name == "email" })?.value
        
        if let expiresString = queryItems.first(where: { $0.name == "expires" })?.value,
           let expiresInterval = TimeInterval(expiresString) {
            self.expiresAt = Date(timeIntervalSince1970: expiresInterval)
        } else {
            self.expiresAt = nil
        }
    }
    
    var isExpired: Bool {
        guard let expiresAt = expiresAt else { return false }
        return Date() > expiresAt
    }
}

// MARK: - Universal Link Router

enum DeepLinkDestination {
    case passwordReset(PasswordResetDeepLink)
    case unknown
}

class UniversalLinkRouter {
    
    static let shared = UniversalLinkRouter()
    
    private init() {}
    
    func route(url: URL) -> DeepLinkDestination {
        if let resetLink = PasswordResetDeepLink(url: url) {
            return .passwordReset(resetLink)
        }
        return .unknown
    }
}

// MARK: - Navigation Coordinator

protocol NavigationCoordinatorDelegate: AnyObject {
    func didCompletePasswordReset()
    func didCancelPasswordReset()
    func didFailPasswordReset(error: Error)
}

class NavigationCoordinator {
    
    static let shared = NavigationCoordinator()
    
    weak var delegate: NavigationCoordinatorDelegate?
    private weak var navigationController: UINavigationController?
    
    private init() {}
    
    func setRootNavigationController(_ navController: UINavigationController) {
        self.navigationController = navController
    }
    
    func handleUniversalLink(_ url: URL) -> Bool {
        let destination = UniversalLinkRouter.shared.route(url: url)
        
        switch destination {
        case .passwordReset(let deepLink):
            navigateToPasswordReset(deepLink: deepLink)
            return true
        case .unknown:
            return false
        }
    }
    
    private func navigateToPasswordReset(deepLink: PasswordResetDeepLink) {
        guard !deepLink.isExpired else {
            showExpiredTokenAlert()
            return
        }
        
        DispatchQueue.main.async { [weak self] in
            guard let self = self, let navController = self.navigationController else { return }
            
            // Dismiss any presented view controllers first
            if let presented = navController.presentedViewController {
                presented.dismiss(animated: false) {
                    self.presentPasswordResetScreen(on: navController, deepLink: deepLink)
                }
            } else {
                self.presentPasswordResetScreen(on: navController, deepLink: deepLink)
            }
        }
    }
    
    private func presentPasswordResetScreen(on navController: UINavigationController, deepLink: PasswordResetDeepLink) {
        let resetVC = PasswordResetViewController(deepLink: deepLink)
        resetVC.delegate = self
        
        let resetNavController = UINavigationController(rootViewController: resetVC)
        resetNavController.modalPresentationStyle = .fullScreen
        navController.present(resetNavController, animated: true)
    }
    
    private func showExpiredTokenAlert() {
        DispatchQueue.main.async { [weak self] in
            guard let navController = self?.navigationController else { return }
            
            let alert = UIAlertController(
                title: "Link Expired",
                message: "This password reset link has expired. Please request a new one.",
                preferredStyle: .alert
            )
            alert.addAction(UIAlertAction(title: "Request New Link", style: .default) { _ in
                // Navigate to forgot password screen
                let forgotPasswordVC = ForgotPasswordViewController()
                navController.pushViewController(forgotPasswordVC, animated: true)
            })
            alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
            
            let presenter = navController.presentedViewController ?? navController
            presenter.present(alert, animated: true)
        }
    }
}

